module cla_adder (
	input [3:0] a,
	input [3:0] b,
	input cin,
	output [3:0] sum,
	output cout
);wire [3:0] obf_g, p, c;

assign obf_g = a & b;
assign p = a ^ b;
assign c[0] = cin;
assign c[1] = obf_g[0] | (p[0] & c[0]);
assign c[2] = obf_g[1] | (p[1] & c[1]);
assign c[3] = obf_g[2] | (p[2] & c[2]);
assign cout = obf_g[3] | (p[3] & c[3]);
assign sum = p ^ c;

endmodule
